parameters.query:
SELECT id, word, translation, context, ease_factor, interval, repetitions
FROM vocabulary
WHERE user_id = {{ $json.id }}
  AND next_review <= NOW()
ORDER BY next_review ASC
LIMIT 5;

parameters.jsCode:
const user = $('For Each User').item.json;
const words = $input.all().map(i => i.json);
const userId = user.id;
const nowMs = Date.now();

const state = {
  type: 'flashcard',
  cards: words.map(w => ({
    vocabId: w.id,
    word: w.word,
    translation: w.translation || '',
    context: w.context || '',
    easeFactor: parseFloat(w.ease_factor) || 2.5,
    interval: parseInt(w.interval) || 1,
    repetitions: parseInt(w.repetitions) || 0
  })),
  current: 0,
  results: [],
  hintUsed: false,
  sentAt: [nowMs],
  startedAt: nowMs,
  nativeLang: user.native_lang || 'en',
  targetLang: user.target_lang || 'en',
  level: user.level || 'A1'
};

return [{ json: {
  userId,
  firstName: user.first_name || 'friend',
  stateJson: JSON.stringify(state),
  state,
  nativeLang: state.nativeLang
} }];

parameters.query:
INSERT INTO daily_lesson_sessions (user_id, card_count, status)
VALUES ({{ $json.userId }}, {{ $json.state.cards.length }}, 'sent')
RETURNING id;

parameters.jsCode:
const sessionId = $('Insert Session Record').item.json.id;
const built = $('Build Flashcard Session').item.json;

const state = { ...built.state, sessionId };

return [{ json: {
  ...built,
  stateJson: JSON.stringify(state),
  state,
  sessionId
} }];

parameters.body:
={{ (function() {
  const data = $('Attach Session ID').item.json;
  const userId = data.userId;
  const state = data.state;
  const card = state.cards[0];
  const total = state.cards.length;
  const nativeLang = state.nativeLang;

  const MORNING = {
    ru: 'Доброе утро', en: 'Good morning', es: 'Buenos días',
    de: 'Guten Morgen', fr: 'Bonjour', zh: '早上好',
    ar: 'صباح الخير', pt: 'Bom dia', hi: 'सुप्रभात',
    ja: 'おはようございます', ko: '좋은 아침', tr: 'Günaydın',
    uk: 'Доброго ранку', pl: 'Dzień dobry'
  };
  const LABELS = {
    ru: { card: 'Карточка', know: '✅ Знаю', dontKnow: '❌ Не знаю' },
    en: { card: 'Card', know: '✅ Know', dontKnow: "❌ Don't know" },
    es: { card: 'Tarjeta', know: '✅ Sé', dontKnow: '❌ No sé' },
    de: { card: 'Karte', know: '✅ Kenne', dontKnow: '❌ Kenne nicht' },
    fr: { card: 'Carte', know: '✅ Je sais', dontKnow: '❌ Je ne sais pas' },
    zh: { card: '卡片', know: '✅ 认识', dontKnow: '❌ 不认识' },
    uk: { card: 'Картка', know: '✅ Знаю', dontKnow: '❌ Не знаю' },
    pl: { card: 'Karta', know: '✅ Znam', dontKnow: '❌ Nie znam' }
  };
  const greeting = MORNING[nativeLang] || MORNING['en'];
  const L = LABELS[nativeLang] || LABELS['en'];

  const text = greeting + ', ' + data.firstName + '! ☀️\n\n' +
    L.card + ' 1/' + total + '\n\n' +
    '*' + card.word + '*' +
    (card.context ? '\n\n_"' + card.context + '"_' : '');

  return JSON.stringify({
    chat_id: userId,
    text,
    parse_mode: 'Markdown',
    reply_markup: { inline_keyboard: [[
      { text: L.know, callback_data: 'daily_ans_know' },
      { text: L.dontKnow, callback_data: 'daily_ans_dontknow' }
    ]]}
  });
})() }}
